DROP TABLE `vw_calendar_meetings`;
DROP VIEW IF EXISTS `vw_calendar_meetings`;
CREATE VIEW `vw_calendar_meetings` AS select `m`.`id` AS `id`,`m`.`post_initiative_id` AS `post_initiative_id`,`m`.`communication_id` AS `communication_id`,`m`.`is_current` AS `is_current`,`m`.`status_id` AS `status_id`,`m`.`type_id` AS `type_id`,`m`.`date` AS `date`,`m`.`reminder_date` AS `reminder_date`,`m`.`notes` AS `notes`,`m`.`created_at` AS `created_at`,`m`.`created_by` AS `created_by`,`m`.`location_id` AS `location_id`,`m`.`nbm_predicted_rating` AS `nbm_predicted_rating`,`m`.`feedback_rating` AS `feedback_rating`,`m`.`feedback_decision_maker` AS `feedback_decision_maker`,`m`.`feedback_agency_user` AS `feedback_agency_user`,`m`.`feedback_budget_available` AS `feedback_budget_available`,`m`.`feedback_receptive` AS `feedback_receptive`,`m`.`feedback_targeting` AS `feedback_targeting`,`m`.`feedback_meeting_length` AS `feedback_meeting_length`,`m`.`feedback_comments` AS `feedback_comments`,`m`.`feedback_next_steps` AS `feedback_next_steps`,`cli`.`id` AS `client_id`,`cli`.`name` AS `client`,`c`.`id` AS `company_id`,`c`.`name` AS `company`,`pi`.`post_id` AS `post_id`, `pi`.`initiative_id` as `initiative_id` from ((((((`tbl_meetings` `m` join `tbl_post_initiatives` `pi` on((`m`.`post_initiative_id` = `pi`.`id`))) join `tbl_posts` `p` on((`pi`.`post_id` = `p`.`id`))) join `tbl_companies` `c` on((`p`.`company_id` = `c`.`id`))) join `tbl_initiatives` `i` on((`pi`.`initiative_id` = `i`.`id`))) join `tbl_campaigns` `cam` on((`i`.`campaign_id` = `cam`.`id`))) join `tbl_clients` `cli` on((`cam`.`client_id` = `cli`.`id`)));
